import { request, authRequest } from "./api";
import { Course, UserProgress } from "../types/api.types";

// Интерфейс для ответа от /users/me
interface UserMeResponse {
  user: {
    email: string;
    selectedCourses: string[];
  };
}

// Моковые данные для тестирования
const mockCourses: Course[] = [
  {
    _id: "1",
    nameRU: "Йога",
    nameEN: "Yoga",
    description: "Йога для начинающих",
    directions: [],
    fitting: [],
    difficulty: "Начальный",
    durationInDays: 25,
    dailyDurationInMinutes: { from: 20, to: 50 },
    workouts: ["w1", "w2", "w3", "w4", "w5"],
  },
  {
    _id: "2",
    nameRU: "Стретчинг",
    nameEN: "Stretching",
    description: "Растяжка для всего тела",
    directions: [],
    fitting: [],
    difficulty: "Средний",
    durationInDays: 25,
    dailyDurationInMinutes: { from: 20, to: 50 },
    workouts: ["w1", "w2", "w3", "w4", "w5"],
  },
  {
    _id: "3",
    nameRU: "Фитнес",
    nameEN: "Fitness",
    description: "Интенсивные тренировки",
    directions: [],
    fitting: [],
    difficulty: "Продвинутый",
    durationInDays: 25,
    dailyDurationInMinutes: { from: 20, to: 50 },
    workouts: ["w1", "w2", "w3", "w4", "w5"],
  },
];

// Ключ для хранения курсов пользователя в localStorage
const USER_COURSES_KEY = "user_selected_courses";

export const coursesService = {
  // Получить все курсы
  async getAllCourses(): Promise<Course[]> {
    try {
      return await request("/courses");
    } catch (error) {
      console.warn("API недоступен, используем моковые данные");
      return mockCourses;
    }
  },

  // Получить курс по ID
  async getCourseById(courseId: string): Promise<Course> {
    try {
      return await request(`/courses/${courseId}`);
    } catch (error) {
      console.warn("API недоступен, ищем в моковых данных");
      const course = mockCourses.find((c) => c._id === courseId);
      if (!course) throw new Error("Курс не найден");
      return course;
    }
  },

  // Получить курсы пользователя
  async getUserCourses(token: string): Promise<string[]> {
    try {
      const response = await authRequest<UserMeResponse>("/users/me", token);
      return response.user.selectedCourses || [];
    } catch (error) {
      console.warn("API недоступен, используем localStorage");

      // Получаем сохраненные курсы из localStorage
      const saved = localStorage.getItem(USER_COURSES_KEY);
      if (saved) {
        return JSON.parse(saved);
      }

      // Для теста возвращаем только 3 курса
      const defaultCourses = ["1", "2", "3"];
      localStorage.setItem(USER_COURSES_KEY, JSON.stringify(defaultCourses));
      return defaultCourses;
    }
  },

  // Получить прогресс пользователя по курсу
  async getUserCourseProgress(
    courseId: string,
    token: string,
  ): Promise<UserProgress> {
    try {
      return await authRequest(
        `/users/me/progress?courseId=${courseId}`,
        token,
      );
    } catch (error) {
      console.warn("API недоступен, возвращаем пустой прогресс");
      return {
        courseId,
        courseCompleted: false,
        workoutsProgress: [],
      };
    }
  },

  // Получить прогресс по конкретной тренировке
  async getWorkoutProgress(
    courseId: string,
    workoutId: string,
    token: string,
  ): Promise<{
    workoutId: string;
    workoutCompleted: boolean;
    progressData: number[];
  }> {
    try {
      return await authRequest(
        `/users/me/progress?courseId=${courseId}&workoutId=${workoutId}`,
        token,
      );
    } catch (error) {
      console.warn("API недоступен, возвращаем пустой прогресс");
      return {
        workoutId,
        workoutCompleted: false,
        progressData: [],
      };
    }
  },

  // Добавить курс пользователю
  async addCourseToUser(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    try {
      return await authRequest("/users/me/courses", token, {
        method: "POST",
        body: JSON.stringify({ courseId }),
      });
    } catch (error) {
      console.warn("API недоступен, сохраняем в localStorage");

      const saved = localStorage.getItem(USER_COURSES_KEY);
      const courses = saved ? JSON.parse(saved) : [];
      if (!courses.includes(courseId)) {
        courses.push(courseId);
        localStorage.setItem(USER_COURSES_KEY, JSON.stringify(courses));
      }

      return { message: "Курс успешно добавлен (тестовый режим)" };
    }
  },

  // Удалить курс у пользователя
  async removeCourseFromUser(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    try {
      return await authRequest(`/users/me/courses/${courseId}`, token, {
        method: "DELETE",
      });
    } catch (error) {
      console.warn("API недоступен, удаляем из localStorage");

      const saved = localStorage.getItem(USER_COURSES_KEY);
      if (saved) {
        const courses = JSON.parse(saved).filter(
          (id: string) => id !== courseId,
        );
        localStorage.setItem(USER_COURSES_KEY, JSON.stringify(courses));
      }

      return { message: "Курс успешно удален (тестовый режим)" };
    }
  },

  // Сбросить прогресс по курсу
  async resetCourseProgress(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    try {
      return await authRequest(`/courses/${courseId}/reset`, token, {
        method: "PATCH",
      });
    } catch (error) {
      console.warn("API недоступен, имитируем сброс прогресса");
      return { message: "Прогресс курса сброшен (тестовый режим)" };
    }
  },
};
